module up_down_counter(
    input wire clk,
    input wire rst_n,
    input wire up_down,
    output reg [3:0] count
    );

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n)
        count <= 4'd0;
    else if (up_down)
        count <= count + 4'd1;
    else
        count <= count - 4'd1;
end

endmodule
